@startuml
skinparam classAttributeIconSize 0
skinparam classFontStyle bold
skinparam classBackgroundColor #F5F5F5
skinparam classBorderColor #333333
skinparam classArrowColor #333333
skinparam classStereotypeStyle none

class Client {
}

class Context {
  + currentState: State
  + request()
}

interface State {
  + handle()
}

class StateOne {
  + handle()
}

class StateTwo {
  + handle()
}

Client --> Context
Context o-- State
State <|-- StateOne
State <|-- StateTwo

note right of Context
  <color:red>□</color> currentState:State
  <color:green>●</color> request()
end note

note right of State
  <color:green>●</color> handle()
end note

note right of StateOne
  <color:green>●</color> handle()
end note

note right of StateTwo
  <color:green>●</color> handle()
end note

@enduml
